        <svg class="header-icon" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="M12 2 L15.09 8.26 L22 9.27 L17 14.14 L18.18 21.02 L12 17.77 L5.82 21.02 L7 14.14 L2 9.27 L8.91 8.26 L12 2z" />
        </svg>
        <div class="header-title">Tide Options // 潮汐选择</div>
      </div>

      <div class="header-controls">
        <span class="toggle-label">直接发送</span>
        <div class="toggle-switch" id="directSendToggle"></div>
      </div>
    </div>
    <div class="option-list" id="listRoot"></div>
  </div>

  <script>
    (function() {
      // 背景潮汐流（性能优化版）
      const canvas = document.getElementById('bgCanvas');
      const ctx = canvas.getContext('2d');
      let w, h;
      let animationId = null;

      const isMobile = /Mobi|Android|iPhone|iPad|iPod/i.test(navigator.userAgent);
      const particleFactor = isMobile ? 0.6 : 1.0;

      const waves = [];
      const bubbles = [];
      const sparkles = [];

      function initCanvas() {
        // 获取实际内容高度（包含所有选项后的高度）
        const bodyRect = document.body.getBoundingClientRect();
        w = canvas.width = bodyRect.width;
        h = canvas.height = bodyRect.height;

        // 波浪层
        const waveCount = Math.floor((w * h) / (8000 / particleFactor));
        waves.length = 0;
        for (let i = 0; i < waveCount; i++) {
          waves.push({
            x: Math.random() * w,
            y: Math.random() * h,
            r: 1 + Math.random() * 2,
            baseAlpha: 0.15 + Math.random() * 0.25,
            speedX: 0.1 + Math.random() * 0.3,
            speedY: 0.02 + Math.random() * 0.08,
            phase: Math.random() * Math.PI * 2,
            layer: Math.floor(Math.random() * 3)
          });
        }

        // 气泡层
        const bubbleCount = Math.floor((w * h) / (15000 / particleFactor));
        bubbles.length = 0;
        for (let i = 0; i < bubbleCount; i++) {
          bubbles.push({
            x: Math.random() * w,
            y: Math.random() * h,
            r: 0.5 + Math.random() * 1.5,
            speedY: 0.2 + Math.random() * 0.4,
            wobble: Math.random() * Math.PI * 2,
            alpha: 0.1 + Math.random() * 0.3
          });
        }

        // 微光层
        const sparkleCount = Math.floor((w * h) / (12000 / particleFactor));
        sparkles.length = 0;
        for (let i = 0; i < sparkleCount; i++) {
          sparkles.push({
            x: Math.random() * w,
            y: Math.random() * h,
            r: 0.3 + Math.random() * 0.8,
            phase: Math.random() * Math.PI * 2,
            twinkleSpeed: 0.001 + Math.random() * 0.002
          });
        }
      }

      function drawTide() {
        ctx.clearRect(0, 0, w, h);
        const now = Date.now();
        const tidePhase = now * 0.0002;
        const tideStrength = 0.5 + 0.5 * Math.sin(tidePhase);

        // 波浪层
        waves.forEach(s => {
          const tideBoost = 1 + tideStrength * 0.5 * (s.layer + 1) * 0.5;
          s.x += s.speedX * tideBoost;
          s.y += Math.sin(now * 0.001 + s.phase) * s.speedY;
          if (s.x > w + 10) s.x = -10;
          if (s.y > h + 10) s.y = -10;
          if (s.y < -10) s.y = h + 10;

          const alphaWave = Math.sin(now * 0.0005 + s.phase) * 0.3 + 0.7;
          ctx.globalAlpha = s.baseAlpha * alphaWave * (0.5 + tideStrength * 0.5);
          const colors = ['#4a90d9', '#5fb4e6', '#7fc9ff'];
          ctx.fillStyle = colors[s.layer];
          ctx.beginPath();
          ctx.arc(s.x, s.y, s.r * (1 + s.layer * 0.3), 0, Math.PI * 2);
          ctx.fill();
        });

        // 气泡层
        ctx.fillStyle = '#a8d8ff';
        bubbles.forEach(b => {
          b.y -= b.speedY;
          b.wobble += 0.02;
          b.x += Math.sin(b.wobble) * 0.3;
          if (b.y < -10) {
            b.y = h + 10;
            b.x = Math.random() * w;
          }
          const heightFade = 1 - (h - b.y) / h * 0.5;
          ctx.globalAlpha = b.alpha * heightFade;
          ctx.beginPath();
          ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
          ctx.fill();
        });

        // 微光层
        sparkles.forEach(sp => {
          const twinkle = Math.sin(now * sp.twinkleSpeed + sp.phase);
          const tideGlow = 0.3 + tideStrength * 0.7;
          ctx.globalAlpha = Math.max(0, twinkle * 0.5 + 0.5) * 0.6 * tideGlow;
          ctx.fillStyle = '#c2e4ff';
          ctx.beginPath();
          ctx.arc(sp.x, sp.y, sp.r * (0.8 + tideStrength * 0.4), 0, Math.PI * 2);
          ctx.fill();
        });

        animationId = requestAnimationFrame(drawTide);
      }

      // 更新 canvas 尺寸以匹配内容高度
      function resizeCanvasToContent() {
        if (!canvas) return;
        const bodyRect = document.body.getBoundingClientRect();
        if (bodyRect.width !== w || bodyRect.height !== h) {
          w = canvas.width = bodyRect.width;
          h = canvas.height = bodyRect.height;
          // 重新初始化粒子以适应新尺寸
          initCanvas();
        }
      }

      window.addEventListener('load', () => {
        initCanvas();
        drawTide();
        window.addEventListener('resize', () => {
          resizeCanvasToContent();
        });
      });

      window.addEventListener('beforeunload', () => {
        if (animationId) cancelAnimationFrame(animationId);
      });

      // 2. 解析内容并生成按钮
      function parseAndRender() {
        const rawDiv = document.getElementById('raw-data');
        const listRoot = document.getElementById('listRoot');
        const content = rawDiv.innerHTML;

        const optionsMatch = content.match(/<choice>([\s\S]*?)<\/choice>/i);

        if (!optionsMatch) {
          listRoot.innerHTML = '<div style="padding:10px; color:#ef4444; font-size:12px;">No choice data found in stream.</div>';
          return;
        }

        const lines = optionsMatch[1].split(/\r?\n/);
        let index = 1;
        let found = false;

        for (let line of lines) {
          line = line.trim();
          if (line === '') continue;

          const match = line.match(/^\d+[\.\、\)]\s*(.*)/);
          let optionText = line;
          if (match) {
            optionText = match[1].trim();
          } else {
            optionText = line;
          }
          if (optionText === '') continue;

          found = true;
          const btn = document.createElement('div');
          btn.className = 'option-btn';
          const idxStr = index.toString().padStart(2, '0');

          btn.innerHTML = `
            <span class="option-index">${idxStr}</span>
            <span>${escapeHtml(optionText)}</span>
          `;

          btn.onclick = () => handleSelect(optionText);
          listRoot.appendChild(btn);
          index++;
        }

        if (!found) {
          listRoot.innerHTML = '<div style="padding:10px; color:#94a3b8; font-size:12px;">Empty choice list.</div>';
        }

        // 内容变化后更新 canvas 尺寸
        setTimeout(() => resizeCanvasToContent(), 50);
      }

      function escapeHtml(str) {
        return str.replace(/[&<>]/g, function(m) {
          if (m === '&') return '&amp;';
          if (m === '<') return '&lt;';
          if (m === '>') return '&gt;';
          return m;
        });
      }

      let directSend = true;

      function initToggle() {
        const toggle = document.getElementById('directSendToggle');
        if (!toggle) return;

        try {
          const st = window.top.window.SillyTavern;
          if (st) {
            const ctx = st.getContext();
            if (ctx.extensionSettings && ctx.extensionSettings.TideOptions) {
              if (ctx.extensionSettings.TideOptions.directSend !== undefined) {
                directSend = ctx.extensionSettings.TideOptions.directSend;
              }
            }
          }
        } catch (e) { console.error("Error reading settings", e); }

        if (directSend) toggle.classList.add('active');
        else toggle.classList.remove('active');

        toggle.onclick = (e) => {
          e.stopPropagation();
          directSend = !directSend;
          toggle.classList.toggle('active', directSend);

          try {
            const st = window.top.window.SillyTavern;
            if (st) {
              const ctx = st.getContext();
              if (!ctx.extensionSettings.TideOptions) ctx.extensionSettings.TideOptions = {};
              ctx.extensionSettings.TideOptions.directSend = directSend;
              if (st.saveSettingsDebounced) st.saveSettingsDebounced();
              else if (ctx.saveSettingsDebounced) ctx.saveSettingsDebounced();
            }
          } catch (e) { console.error("Error saving settings", e); }
        };
      }

      function handleSelect(text) {
        try {
          if (window.parent) {
            const parentDoc = window.parent.document;
            const textarea = parentDoc.getElementById('send_textarea');

            if (textarea) {
              textarea.value = text;
              textarea.dispatchEvent(new Event('input', { bubbles: true }));
              textarea.dispatchEvent(new Event('change', { bubbles: true }));

              if (directSend) {
                if (window.parent.SillyTavern && window.parent.SillyTavern.getContext) {
                  const context = window.parent.SillyTavern.getContext();
                  if (context && context.generate) context.generate();
                } else {
                  const sendBtn = parentDoc.getElementById('send_but');
                  if (sendBtn) sendBtn.click();
                }
                // 注意：不移除 iframe，保留面板
              }
            }
          }
        } catch (e) {
          console.error("Tide Options Error:", e);
          alert("Interaction failed. See console.");
        }
      }

      function updateHeight() {
        const height = document.body.scrollHeight;
        if (window.parent && window.parent !== window) {
          window.parent.postMessage({ type: 'resizeIframe', height: height }, '*');
        }
        // 更新 canvas 尺寸
        resizeCanvasToContent();
      }

      window.addEventListener('load', () => {
        parseAndRender();
        initToggle();
      });

      const observer = new MutationObserver(() => {
        updateHeight();
      });
      observer.observe(document.body, { childList: true, subtree: true });
    })();
  </script>
</body>
</html>
