  <title>潮汐抉择</title>
  <style>
    :root {
      --tide-deep: #051a2e;
      --tide-mid: #0d2b45;
      --tide-shallow: #1a4a6e;
      --tide-surface: #2d6a9f;
      --tide-foam: #7fc9ff;
      --tide-glow: #a8e6ff;
      --tide-text: #e0f7ff;
